     1→# Trash Bin Feature - Implementation Plan
     2→
     3→## Overview
     4→
     5→This document outlines the implementation for a Trash Bin feature in the shaRe platform. Documents are never truly deleted - instead, they are soft-deleted using date-based relationships.
     6→
     7→## Date Pattern
     8→
     9→The codebase already uses a `start`/`end` date pattern in `SeatRelationship` (roundtables):
    10→```typescript
    11→interface SeatRelationship {
    12→  id: string;
    13→  start: string;
    14→  end: string | null;  // null = active
    15→}
    16→```
    17→
    18→We'll use the same pattern for document relationships:
    19→- `validFrom`: When the relationship started (set on creation)
    20→- `validUntil`: When the document was deleted (null = active, set = in trash)
    21→
    22→---
    23→
    24→## Part 1: Backend (operator-ts)
    25→
    26→### 1.1 DocumentsRepository Changes
    27→
    28→**File:** `src/documents/documents.repository.ts`
    29→
    30→#### Add new methods:
    31→
    32→```typescript
    33→/**
    34→ * Move document to trash (soft-delete)
    35→ * Sets validUntil on all BELONGS_TO, SHARED_WITH, CONTRIBUTED_TO relationships
    36→ */
    37→async moveToTrash(documentId: string): Promise<void> {
    38→  const now = new Date().toISOString();
    39→  
    40→  // Set validUntil on BELONGS_TO relationships
    41→  await this.neo4jService.writeVoid(
    42→    `MATCH (d:Document {id: $documentId})-[r:BELONGS_TO]->(ctx)
    43→     SET r.validUntil = $now
    44→     RETURN d`,
    45→    { documentId, now }
    46→  );
    47→  
    48→  // Set validUntil on SHARED_WITH relationships
    49→  await this.neo4jService.writeVoid(
    50→    `MATCH (d:Document {id: $documentId})-[r:SHARED_WITH]->(sh)
    51→     SET r.validUntil = $now
    52→     RETURN d`,
    53→    { documentId, now }
    54→  );
    55→  
    56→  // Set validUntil on CONTRIBUTED_TO relationships
    57→  await this.neo4jService.writeVoid(
    58→    `MATCH (d:Document {id: $documentId})-[r:CONTRIBUTED_TO]->(rt)
    59→     SET r.validUntil = $now
    60→     RETURN d`,
    61→    { documentId, now }
    62→  );
    63→  
    64→  this.logger.log(`Document ${documentId} moved to trash`);
    65→}
    66→
    67→/**
    68→ * Restore document from trash (undelete)
    69→ * Creates new BELONGS_TO relationship with validUntil = NULL
    70→ */
    71→async restoreFromTrash(
    72→  documentId: string,
    73→  contextType: ContextType,
    74→  contextId: string,
    75→): Promise<void> {
    76→  const now = new Date().toISOString();
    77→  const contextLabel = this.contextLabel(contextType);
    78→  
    79→  // Check if already restored to this context
    80→  const existingRel = await this.neo4jService.querySingleObject(
    81→    `MATCH (d:Document {id: $documentId})-[r:BELONGS_TO]->(ctx:${contextLabel} {id: $contextId})
    82→     WHERE r.validUntil IS NULL
    83→     RETURN r`,
    84→    { documentId, contextId }
    85→  );
    86→  
    87→  if (existingRel) {
    88→    return; // Already restored
    89→  }
    90→  
    91→  // Create new BELONGS_TO relationship with null validUntil
    92→  await this.neo4jService.writeVoid(
    93→    `MATCH (d:Document {id: $documentId})
    94→     MATCH (ctx:${contextLabel} {id: $contextId})
    95→     CREATE (d)-[:BELONGS_TO {validFrom: $now, validUntil: NULL}]->(ctx)
    96→     RETURN d`,
    97→    { documentId, contextId, now }
    98→  );
    99→  
   100→  this.logger.log(`Document ${documentId} restored to ${contextType}:${contextId}`);
   101→}
   102→
   103→/**
   104→ * Get all trashed documents for a shareholder
   105→ */
   106→async getTrashedDocuments(shareholderId: string): Promise<Document[]> {
   107→  const result = await this.neo4jService.query(
   108→    `MATCH (d:Document)-[r:BELONGS_TO]->(ctx)
   109→     WHERE r.validUntil IS NOT NULL
   110→     OPTIONAL MATCH (d)-[:CREATED_BY]->(creator:Shareholder)
   111→     OPTIONAL MATCH (d)-[:LAST_MODIFIED_BY]->(modifier:Shareholder)
   112→     WHERE creator.id = $shareholderId OR modifier.id = $shareholderId
   113→     RETURN d, creator.id AS createdByShareholderId, modifier.id AS lastModifiedByShareholderId
   114→     ORDER BY r.validUntil DESC
   115→     LIMIT 500`,
   116→    { shareholderId }
   117→  );
   118→  
   119→  return result.map((record) => this.mapDocument(record));
   120→}
   121→
   122→/**
   123→ * Permanently delete a document
   124→ */
   125→async permanentDelete(documentId: string): Promise<void> {
   126→  await this.neo4jService.writeVoid(
   127→    `MATCH (d:Document {id: $documentId})
   128→     OPTIONAL MATCH (d)-[r]-()
   129→     OPTIONAL MATCH (v:DocumentVersion)-[:VERSION_OF]->(d)
   130→     OPTIONAL MATCH (v)-[vr]-()
   131→     DELETE vr, v, r, d`,
   132→    { documentId }
   133→  );
   134→  
   135→  this.logger.log(`Document ${documentId} permanently deleted`);
   136→}
   137→```
   138→
   139→#### Modify existing `getByContext` method:
   140→
   141→Add filter to exclude trashed documents:
   142→```typescript
   143→async getByContext(contextType: ContextType, contextId: string): Promise<Document[]> {
   144→  // For ROUNDTABLE: check both BELONGS_TO and CONTRIBUTED_TO
   145→  if (contextType === ContextType.ROUNDTABLE) {
   146→    const result = await this.neo4jService.query(
   147→      `MATCH (d:Document)-[r:BELONGS_TO]->(rt:Roundtable {id: $contextId})
   148→       WHERE r.validUntil IS NULL  -- ADD THIS LINE: exclude trashed
   149→       OPTIONAL MATCH (d)-[:CREATED_BY]->(creator:Shareholder)
   150→       ...
   151→       UNION
   152→       MATCH (d:Document)-[r:CONTRIBUTED_TO]->(rt:Roundtable {id: $contextId})
   153→       WHERE r.validUntil IS NULL  -- ADD THIS LINE: exclude trashed
   154→       ...`
   155→    );
   156→  }
   157→  // For other contexts...
   158→}
   159→```
   160→
   161→#### Modify `create` method:
   162→
   163→Add `validFrom` to BELONGS_TO relationship:
   164→```typescript
   165→CREATE (d)-[:BELONGS_TO {validFrom: datetime($createdAt), validUntil: NULL}]->(ctx)
   166→```
   167→
   168→---
   169→
   170→### 1.2 DocumentsService Changes
   171→
   172→**File:** `src/documents/documents.service.ts`
   173→
   174→Add new methods:
   175→
   176→```typescript
   177→async moveToTrash(documentId: string, shareholderId: string): Promise<void> {
   178→  // Verify ownership or edit permission
   179→  const doc = await this.documentsRepository.getById(documentId);
   180→  if (!doc) {
   181→    throw new NotFoundException('Document not found');
   182→  }
   183→  
   184→  // Check permission
   185→  const access = await this.accessService.getPermissions(shareholderId, doc);
   186→  if (!access.canEdit) {
   187→    throw new ForbiddenException('No permission to delete this document');
   188→  }
   189→  
   190→  await this.documentsRepository.moveToTrash(documentId);
   191→}
   192→
   193→async restoreFromTrash(
   194→  documentId: string,
   195→  contextType: ContextType,
   196→  contextId: string,
   197→  shareholderId: string,
   198→): Promise<void> {
   199→  const doc = await this.documentsRepository.getById(documentId);
   200→  if (!doc) {
   201→    throw new NotFoundException('Document not found');
   202→  }
   203→  
   204→  // Check permission to access the target context
   205→  const hasAccess = await this.checkContextAccess(shareholderId, contextType, contextId);
   206→  if (!hasAccess) {
   207→    throw new ForbiddenException('No permission to restore to this context');
   208→  }
   209→  
   210→  await this.documentsRepository.restoreFromTrash(documentId, contextType, contextId);
   211→}
   212→
   213→async getTrashedDocuments(shareholderId: string): Promise<Document[]> {
   214→  return this.documentsRepository.getTrashedDocuments(shareholderId);
   215→}
   216→
   217→async permanentDelete(documentId: string, shareholderId: string): Promise<void> {
   218→  // Only allow if document is in trash (check via isInTrash or getTrashedDocuments)
   219→  const isInTrash = await this.documentsRepository.isInTrash(documentId);
   220→  if (!isInTrash) {
   221→    throw new BadRequestException('Can only permanently delete trashed documents');
   222→  }
   223→  
   224→  // Get S3 keys before deleting
   225→  const s3Keys = await this.documentsRepository.getAllS3Keys(documentId);
   226→  
   227→  // Permanent delete from Neo4j
   228→  await this.documentsRepository.permanentDelete(documentId);
   229→  
   230→  // Delete from S3 (MinIO)
   231→  for (const key of s3Keys) {
   232→    await this.minioService.deleteFile(key);
   233→  }
   234→}
   235→
   236→private async checkContextAccess(
   237→  shareholderId: string,
   238→  contextType: ContextType,
   239→  contextId: string,
   240→): Promise<boolean> {
   241→  switch (contextType) {
   242→    case ContextType.ROUNDTABLE:
   243→      return this.documentsRepository.isResponsibleAtRoundtable(shareholderId, contextId);
   244→    case ContextType.SHARE:
   245→      return this.documentsRepository.isResponsibleAtShareRoundtable(shareholderId, contextId);
   246→    case ContextType.COMMUNITY:
   247→      return this.documentsRepository.isShareholderInCommunity(shareholderId, contextId);
   248→    default:
   249→      return false;
   250→  }
   251→}
   252→```
   253→
