   335→
   336→### 2.2 Create TrashView Component
   337→
   338→**File:** `src/components/documents/TrashView.tsx`
   339→
   340→```typescript
   341→import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
   342→import { 
   343→  Box, 
   344→  List, 
   345→  ListItem, 
   346→  ListItemText, 
   347→  IconButton, 
   348→  Typography,
   349→  Button,
   350→  Dialog,
   351→  DialogTitle,
   352→  DialogContent,
   353→  DialogActions,
   354→} from '@mui/material';
   355→import { useState } from 'react';
   356→import { useTranslation } from 'react-i18next';
   357→import RestoreIcon from '@mui/icons-material/Restore';
   358→import DeleteForeverIcon from '@mui/icons-material/DeleteForever';
   359→import { getV2DocumentsTrashOptions, postV2DocumentsIdRestore, deleteV2DocumentsIdPermanent, deleteV2DocumentsById } from '../../client/@tanstack/react-query.gen';
   360→
   361→interface TrashItem {
   362→  id: string;
   363→  name: string;
   364→  contextType: string;
   365→  contextId: string;
   366→  deletedAt: string;
   367→}
   368→
   369→export default function TrashView({ shareholderId }: { shareholderId: string }) {
   370→  const { t } = useTranslation();
   371→  const queryClient = useQueryClient();
   372→  const [selectedItem, setSelectedItem] = useState<TrashItem | null>(null);
   373→  const [restoreDialogOpen, setRestoreDialogOpen] = useState(false);
   374→  const [permanentDeleteDialogOpen, setPermanentDeleteDialogOpen] = useState(false);
   375→  
   376→  // Fetch trashed documents
   377→  const { data: trashedDocs, isLoading } = useQuery({
   378→    ...getV2DocumentsTrashOptions(),
   379→  });
   380→  
   381→  // Restore mutation
   382→  const restoreMutation = useMutation({
   383→    mutationFn: ({ id, contextType, contextId }: { id: string; contextType: string; contextId: string }) =>
   384→      postV2DocumentsIdRestore({ 
   385→        path: { id }, 
   386→        body: { contextType, contextId } 
   387→      }),
   388→    onSuccess: () => {
   389→      queryClient.invalidateQueries({ queryKey: ['v2/documents/trash'] });
   390→      setRestoreDialogOpen(false);
   391→      setSelectedItem(null);
   392→    },
   393→  });
   394→  
   395→  // Permanent delete mutation
   396→  const permanentDeleteMutation = useMutation({
   397→    mutationFn: (id: string) => deleteV2DocumentsIdPermanent({ path: { id } }),
   398→    onSuccess: () => {
   399→      queryClient.invalidateQueries({ queryKey: ['v2/documents/trash'] });
   400→      setPermanentDeleteDialogOpen(false);
   401→      setSelectedItem(null);
   402→    },
   403→  });
   404→  
   405→  const handleRestore = (item: TrashItem) => {
   406→    setSelectedItem(item);
   407→    setRestoreDialogOpen(true);
   408→  };
   409→  
   410→  const handlePermanentDelete = (item: TrashItem) => {
   411→    setSelectedItem(item);
   412→    setPermanentDeleteDialogOpen(true);
   413→  };
   414→  
   415→  const confirmRestore = () => {
   416→    if (selectedItem) {
   417→      restoreMutation.mutate({
   418→        id: selectedItem.id,
   419→        contextType: selectedItem.contextType,
   420→        contextId: selectedItem.contextId,
   421→      });
   422→    }
   423→  };
   424→  
   425→  const confirmPermanentDelete = () => {
   426→    if (selectedItem) {
   427→      permanentDeleteMutation.mutate(selectedItem.id);
   428→    }
   429→  };
   430→  
   431→  if (isLoading) {
   432→    return <Box p={2}>{t('common.loading')}</Box>;
   433→  }
   434→  
   435→  if (!trashedDocs || trashedDocs.length === 0) {
   436→    return (
   437→      <Box p={4} textAlign="center">
   438→        <DeleteForeverIcon sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
   439→        <Typography color="text.secondary">
   440→          {t('documents.trashEmpty')}
   441→        </Typography>
   442→      </Box>
   443→    );
   444→  }
   445→  
   446→  return (
   447→    <Box>
   448→      <List>
   449→        {trashedDocs.map((doc: any) => (
   450→          <ListItem
   451→            key={doc.id}
   452→            secondaryAction={
   453→              <Box>
   454→                <IconButton 
   455→                  onClick={() => handleRestore(doc)}
   456→                  title={t('documents.restore')}
   457→                >
   458→                  <RestoreIcon />
   459→                </IconButton>
   460→                <IconButton 
   461→                  onClick={() => handlePermanentDelete(doc)}
   462→                  title={t('documents.deletePermanently')}
   463→                  color="error"
   464→                >
   465→                  <DeleteForeverIcon />
   466→                </IconButton>
   467→              </Box>
   468→            }
   469→          >
   470→            <ListItemText
   471→              primary={doc.name}
   472→              secondary={t('documents.deletedOn', { date: new Date(doc.deletedAt).toLocaleDateString() })}
   473→            />
   474→          </ListItem>
   475→        ))}
   476→      </List>
   477→      
   478→      {/* Restore Dialog */}
   479→      <Dialog open={restoreDialogOpen} onClose={() => setRestoreDialogOpen(false)}>
   480→        <DialogTitle>{t('documents.restoreDocument')}</DialogTitle>
   481→        <DialogContent>
   482→          <Typography>
   483→            {t('documents.restoreConfirm', { name: selectedItem?.name })}
   484→          </Typography>
   485→        </DialogContent>
   486→        <DialogActions>
   487→          <Button onClick={() => setRestoreDialogOpen(false)}>{t('common.cancel')}</Button>
   488→          <Button onClick={confirmRestore} variant="contained">
   489→            {t('documents.restore')}
   490→          </Button>
   491→        </DialogActions>
   492→      </Dialog>
   493→      
   494→      {/* Permanent Delete Dialog */}
   495→      <Dialog open={permanentDeleteDialogOpen} onClose={() => setPermanentDeleteDialogOpen(false)}>
   496→        <DialogTitle>{t('documents.deletePermanently')}</DialogTitle>
   497→        <DialogContent>
   498→          <Typography color="error">
   499→            {t('documents.permanentDeleteWarning', { name: selectedItem?.name })}
   500→          </Typography>
   501→        </DialogContent>
   502→        <DialogActions>
   503→          <Button onClick={() => setPermanentDeleteDialogOpen(false)}>{t('common.cancel')}</Button>
   504→          <Button onClick={confirmPermanentDelete} color="error" variant="contained">
   505→            {t('documents.deletePermanently')}
   506→          </Button>
   507→        </DialogActions>
   508→      </Dialog>
   509→    </Box>
   510→  );
   511→}
   512→```
   513→
   514→### 2.3 Update API Client
   515→
   516→Generate new API methods for:
   517→- `GET /v2/documents/trash`
   518→- `POST /v2/documents/:id/trash`
   519→- `POST /v2/documents/:id/restore`
   520→- `DELETE /v2/documents/:id/permanent`
   521→
   522→---
   523→
   524→## Part 3: Migration
   525→
   526→For existing documents, you need to add `validFrom`/`validUntil` to their existing relationships. Run this Cypher migration:
   527→
   528→```cypher
   529→// Add validFrom/validUntil to existing BELONGS_TO relationships
   530→MATCH (d:Document)-[r:BELONGS_TO]->(ctx)
   531→WHERE r.validFrom IS NULL
   532→SET r.validFrom = coalesce(d.createdAt, datetime()), r.validUntil = NULL
   533→
   534→// Add validFrom/validUntil to existing SHARED_WITH relationships
   535→MATCH (d:Document)-[r:SHARED_WITH]->(sh)
   536→WHERE r.validFrom IS NULL
   537→SET r.validFrom = coalesce(d.createdAt, datetime()), r.validUntil = NULL
   538→
   539→// Add validFrom/validUntil to existing CONTRIBUTED_TO relationships
   540→MATCH (d:Document)-[r:CONTRIBUTED_TO]->(rt)
   541→WHERE r.validFrom IS NULL
   542→SET r.validFrom = coalesce(d.createdAt, datetime()), r.validUntil = NULL
   543→```
   544→
   545→---
   546→
   547→## Testing Checklist
   548→
   549→- [ ] Create document → should have `validFrom` set, `validUntil` = NULL
   550→- [ ] Move to trash → `validUntil` should be set to current time
   551→- [ ] Document should NOT appear in regular document lists
   552→- [ ] Document should appear in Trash Bin
   553→- [ ] Restore document → new `BELONGS_TO` with `validUntil` = NULL created
   554→- [ ] Document should appear in regular document lists again
   555→- [ ] Permanent delete → document completely removed from Neo4j
   556→- [ ] S3 files deleted on permanent delete
   557→
   558→---
   559→
   560→## Estimated Effort
   561→
   562→| Task | Effort |
   563→|------|--------|
   564→| DocumentsRepository changes | 2 hours |
   565→| DocumentsService changes | 2 hours |
   566→| DocumentsController changes | 1 hour |
   567→| Frontend TrashView component | 3 hours |
   568→| Integration testing | 2 hours |
   569→| **Total** | **~10 hours** |

