# Trash Bin Feature - Implementation Plan

## Overview

This document outlines the implementation for a Trash Bin feature in the shaRe platform. Documents are never truly deleted - instead, they are soft-deleted using date-based relationships.

## Date Pattern

The codebase already uses a `start`/`end` date pattern in `SeatRelationship` (roundtables):
```typescript
interface SeatRelationship {
  id: string;
  start: string;
  end: string | null;  // null = active
}
```

We'll use the same pattern for document relationships:
- `validFrom`: When the relationship started (set on creation)
- `validUntil`: When the document was deleted (null = active, set = in trash)

---

## Part 1: Backend (operator-ts)

### 1.1 DocumentsRepository Changes

**File:** `src/documents/documents.repository.ts`

#### Add new methods:

```typescript
/**
 * Move document to trash (soft-delete)
 * Sets validUntil on all BELONGS_TO, SHARED_WITH, CONTRIBUTED_TO relationships
 */
async moveToTrash(documentId: string): Promise<void> {
  const now = new Date().toISOString();

  // Set validUntil on BELONGS_TO relationships
  await this.neo4jService.writeVoid(
    `MATCH (d:Document {id: $documentId})-[r:BELONGS_TO]->(ctx)
     SET r.validUntil = $now
     RETURN d`,
    { documentId, now }
  );

  // Set validUntil on SHARED_WITH relationships
  await this.neo4jService.writeVoid(
    `MATCH (d:Document {id: $documentId})-[r:SHARED_WITH]->(sh)
     SET r.validUntil = $now
     RETURN d`,
    { documentId, now }
  );

  // Set validUntil on CONTRIBUTED_TO relationships
  await this.neo4jService.writeVoid(
    `MATCH (d:Document {id: $documentId})-[r:CONTRIBUTED_TO]->(rt)
     SET r.validUntil = $now
     RETURN d`,
    { documentId, now }
  );

  this.logger.log(`Document ${documentId} moved to trash`);
}

/**
 * Restore document from trash (undelete)
 * Creates new BELONGS_TO relationship with validUntil = NULL
 */
async restoreFromTrash(
  documentId: string,
  contextType: ContextType,
  contextId: string,
): Promise<void> {
  const now = new Date().toISOString();
  const contextLabel = this.contextLabel(contextType);

  // Check if already restored to this context
  const existingRel = await this.neo4jService.querySingleObject(
    `MATCH (d:Document {id: $documentId})-[r:BELONGS_TO]->(ctx:${contextLabel} {id: $contextId})
     WHERE r.validUntil IS NULL
     RETURN r`,
    { documentId, contextId }
  );

  if (existingRel) {
    return; // Already restored
  }

  // Create new BELONGS_TO relationship with null validUntil
  await this.neo4jService.writeVoid(
    `MATCH (d:Document {id: $documentId})
     MATCH (ctx:${contextLabel} {id: $contextId})
     CREATE (d)-[:BELONGS_TO {validFrom: $now, validUntil: NULL}]->(ctx)
     RETURN d`,
    { documentId, contextId, now }
  );

  this.logger.log(`Document ${documentId} restored to ${contextType}:${contextId}`);
}

/**
 * Get all trashed documents for a shareholder
 */
async getTrashedDocuments(shareholderId: string): Promise<Document[]> {
  const result = await this.neo4jService.query(
    `MATCH (d:Document)-[r:BELONGS_TO]->(ctx)
     WHERE r.validUntil IS NOT NULL
     OPTIONAL MATCH (d)-[:CREATED_BY]->(creator:Shareholder)
     OPTIONAL MATCH (d)-[:LAST_MODIFIED_BY]->(modifier:Shareholder)
     WHERE creator.id = $shareholderId OR modifier.id = $shareholderId
     RETURN d, creator.id AS createdByShareholderId, modifier.id AS lastModifiedByShareholderId
     ORDER BY r.validUntil DESC
     LIMIT 500`,
    { shareholderId }
  );

  return result.map((record) => this.mapDocument(record));
}

/**
 * Permanently delete a document
 */
async permanentDelete(documentId: string): Promise<void> {
  await this.neo4jService.writeVoid(
    `MATCH (d:Document {id: $documentId})
     OPTIONAL MATCH (d)-[r]-()
     OPTIONAL MATCH (v:DocumentVersion)-[:VERSION_OF]->(d)
     OPTIONAL MATCH (v)-[vr]-()
     DELETE vr, v, r, d`,
    { documentId }
  );

  this.logger.log(`Document ${documentId} permanently deleted`);
}
```

