```typescript
async moveToTrash(documentId: string, shareholderId: string): Promise<void> {
  // Verify ownership or edit permission
  const doc = await this.documentsRepository.getById(documentId);
  if (!doc) {
    throw new NotFoundException('Document not found');
  }

  // Check permission
  const access = await this.accessService.getPermissions(shareholderId, doc);
  if (!access.canEdit) {
    throw new ForbiddenException('No permission to delete this document');
  }

  await this.documentsRepository.moveToTrash(documentId);
}

async restoreFromTrash(
  documentId: string,
  contextType: ContextType,
  contextId: string,
  shareholderId: string,
): Promise<void> {
  const doc = await this.documentsRepository.getById(documentId);
  if (!doc) {
    throw new NotFoundException('Document not found');
  }

  // Check permission to access the target context
  const hasAccess = await this.checkContextAccess(shareholderId, contextType, contextId);
  if (!hasAccess) {
    throw new ForbiddenException('No permission to restore to this context');
  }

  await this.documentsRepository.restoreFromTrash(documentId, contextType, contextId);
}

async getTrashedDocuments(shareholderId: string): Promise<Document[]> {
  return this.documentsRepository.getTrashedDocuments(shareholderId);
}

async permanentDelete(documentId: string, shareholderId: string): Promise<void> {
  // Only allow if document is in trash (check via isInTrash or getTrashedDocuments)
  const isInTrash = await this.documentsRepository.isInTrash(documentId);
  if (!isInTrash) {
    throw new BadRequestException('Can only permanently delete trashed documents');
  }

  // Get S3 keys before deleting
  const s3Keys = await this.documentsRepository.getAllS3Keys(documentId);

  // Permanent delete from Neo4j
  await this.documentsRepository.permanentDelete(documentId);

  // Delete from S3 (MinIO)
  for (const key of s3Keys) {
    await this.minioService.deleteFile(key);
  }
}

private async checkContextAccess(
  shareholderId: string,
  contextType: ContextType,
  contextId: string,
): Promise<boolean> {
  switch (contextType) {
    case ContextType.ROUNDTABLE:
      return this.documentsRepository.isResponsibleAtRoundtable(shareholderId, contextId);
    case ContextType.SHARE:
      return this.documentsRepository.isResponsibleAtShareRoundtable(shareholderId, contextId);
    case ContextType.COMMUNITY:
      return this.documentsRepository.isShareholderInCommunity(shareholderId, contextId);
    default:
      return false;
  }
}
