### 2.2 Create TrashView Component

**File:** `src/components/documents/TrashView.tsx`

```typescript
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { 
  Box, 
  List, 
  ListItem, 
  ListItemText, 
  IconButton, 
  Typography,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
} from '@mui/material';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import RestoreIcon from '@mui/icons-material/Restore';
import DeleteForeverIcon from '@mui/icons-material/DeleteForever';
import { getV2DocumentsTrashOptions, postV2DocumentsIdRestore, deleteV2DocumentsIdPermanent, deleteV2DocumentsById } from '../../client/@tanstack/react-query.gen';

interface TrashItem {
  id: string;
  name: string;
  contextType: string;
  contextId: string;
  deletedAt: string;
}

export default function TrashView({ shareholderId }: { shareholderId: string }) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [selectedItem, setSelectedItem] = useState<TrashItem | null>(null);
  const [restoreDialogOpen, setRestoreDialogOpen] = useState(false);
  const [permanentDeleteDialogOpen, setPermanentDeleteDialogOpen] = useState(false);

  // Fetch trashed documents
  const { data: trashedDocs, isLoading } = useQuery({
    ...getV2DocumentsTrashOptions(),
  });

  // Restore mutation
  const restoreMutation = useMutation({
    mutationFn: ({ id, contextType, contextId }: { id: string; contextType: string; contextId: string }) =>
      postV2DocumentsIdRestore({ 
        path: { id }, 
        body: { contextType, contextId } 
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['v2/documents/trash'] });
      setRestoreDialogOpen(false);
      setSelectedItem(null);
    },
  });

  // Permanent delete mutation
  const permanentDeleteMutation = useMutation({
    mutationFn: (id: string) => deleteV2DocumentsIdPermanent({ path: { id } }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['v2/documents/trash'] });
      setPermanentDeleteDialogOpen(false);
      setSelectedItem(null);
    },
  });

  const handleRestore = (item: TrashItem) => {
    setSelectedItem(item);
    setRestoreDialogOpen(true);
  };

  const handlePermanentDelete = (item: TrashItem) => {
    setSelectedItem(item);
    setPermanentDeleteDialogOpen(true);
  };

  const confirmRestore = () => {
    if (selectedItem) {
      restoreMutation.mutate({
        id: selectedItem.id,
        contextType: selectedItem.contextType,
        contextId: selectedItem.contextId,
      });
    }
  };

  const confirmPermanentDelete = () => {
    if (selectedItem) {
      permanentDeleteMutation.mutate(selectedItem.id);
    }
  };

  if (isLoading) {
    return <Box p={2}>{t('common.loading')}</Box>;
  }

  if (!trashedDocs || trashedDocs.length === 0) {
    return (
      <Box p={4} textAlign="center">
        <DeleteForeverIcon sx={{ fontSize: 48, color: 'text.secondary', mb: 2 }} />
        <Typography color="text.secondary">
          {t('documents.trashEmpty')}
        </Typography>
      </Box>
    );
  }

  return (
    <Box>
      <List>
        {trashedDocs.map((doc: any) => (
          <ListItem
            key={doc.id}
            secondaryAction={
              <Box>
                <IconButton 
                  onClick={() => handleRestore(doc)}
                  title={t('documents.restore')}
                >
                  <RestoreIcon />
                </IconButton>
                <IconButton 
                  onClick={() => handlePermanentDelete(doc)}
                  title={t('documents.deletePermanently')}
                  color="error"
                >
                  <DeleteForeverIcon />
                </IconButton>
              </Box>
            }
          >
            <ListItemText
              primary={doc.name}
              secondary={t('documents.deletedOn', { date: new Date(doc.deletedAt).toLocaleDateString() })}
            />
          </ListItem>
        ))}
      </List>

      {/* Restore Dialog */}
      <Dialog open={restoreDialogOpen} onClose={() => setRestoreDialogOpen(false)}>
        <DialogTitle>{t('documents.restoreDocument')}</DialogTitle>
        <DialogContent>
          <Typography>
            {t('documents.restoreConfirm', { name: selectedItem?.name })}
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRestoreDialogOpen(false)}>{t('common.cancel')}</Button>
          <Button onClick={confirmRestore} variant="contained">
            {t('documents.restore')}
          </Button>
        </DialogActions>
      </Dialog>

      {/* Permanent Delete Dialog */}
      <Dialog open={permanentDeleteDialogOpen} onClose={() => setPermanentDeleteDialogOpen(false)}>
        <DialogTitle>{t('documents.deletePermanently')}</DialogTitle>
        <DialogContent>
          <Typography color="error">
            {t('documents.permanentDeleteWarning', { name: selectedItem?.name })}
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setPermanentDeleteDialogOpen(false)}>{t('common.cancel')}</Button>
          <Button onClick={confirmPermanentDelete} color="error" variant="contained">
            {t('documents.deletePermanently')}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}
```

