import React from 'react';
import { useTranslation } from 'react-i18next';
import { Camera, RotateCcw, Video } from 'lucide-react';
import styles from './camera/CameraCapture.module.css';
import { useCamera } from '../hooks/useCamera';
import { CanvasConfig } from '../types';

interface CameraCaptureProps {
  config: CanvasConfig;
  onImageCaptured: (imageData: any) => void;
  disabled?: boolean;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ 
  config, 
  onImageCaptured, 
  disabled = false 
}) => {
  const { t } = useTranslation(['camera', 'common', 'errors']);
  const {
    isCapturing,
    cameraError,
    stream,
    facingMode,
    availableCameras,
    selectedCameraId,
    videoRef,
    captureCanvasRef,
    startCamera,
    stopCamera,
    capturePhoto,
    clearError,
    flipCamera,
    selectCamera,
    getCameraDisplayName,
  } = useCamera(config);

  const handleStartCamera = () => {
    if (disabled) return;
    startCamera();
  };

  const handleCapturePhoto = async () => {
    try {
      const result = await capturePhoto();
      onImageCaptured(result);
    } catch (error) {
      console.error('Photo capture failed:', error);
    }
  };

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      if (!isCapturing) {
        handleStartCamera();
      }
    }
  };

  return (
    <>
      <button
        onClick={handleStartCamera}
        onKeyDown={handleKeyDown}
        disabled={disabled}
        className="btn btn-secondary btn-large"
        aria-label={t('camera:buttons.takePhoto')}
      >
        <Camera size={20} aria-hidden="true" />
        {t('common:buttons.takePhoto')}
      </button>

      {isCapturing && (
        <div
          className={styles.modalOverlay}
          role="dialog"
          aria-modal="true"
          aria-labelledby="camera-modal-title"
        >
          <div className={styles.modal}>
            <h3 id="camera-modal-title" className={styles.modalTitle}>
              {t('camera:modal.title')}
            </h3>

            {/* Camera selector - only show when multiple cameras available and no error */}
            {!cameraError && availableCameras.length > 1 && (
              <div className={styles.cameraSelector}>
                <label htmlFor="camera-select" className={styles.selectorLabel}>
                  <Video size={16} aria-hidden="true" />
                  {t('camera:selector.label', { defaultValue: 'Camera' })}
                </label>
                <select
                  id="camera-select"
                  value={selectedCameraId || ''}
                  onChange={(e) => selectCamera(e.target.value)}
                  className={styles.select}
                  aria-label={t('camera:selector.ariaLabel', { defaultValue: 'Select camera device' })}
                >
                  {availableCameras.map((camera) => (
                    <option key={camera.deviceId} value={camera.deviceId}>
                      {getCameraDisplayName(camera)}
                    </option>
                  ))}
                </select>
              </div>
            )}

            {cameraError ? (
              <div className="error-container">
                <div 
                  className="error-box"
                  role="alert"
                  aria-live="assertive"
                >
                  <div className="error-title">{cameraError.message}</div>
                  <p className="error-text">{cameraError.help}</p>
                  <div className="error-help">
                    <p><strong>{t('errors:camera.help.title')}</strong></p>
                    <ul>
                      {(t('errors:camera.help.steps', { returnObjects: true }) as string[]).map((step: string, index: number) => (
                        <li key={index}>{step}</li>
                      ))}
                    </ul>
                  </div>
                </div>
                <div className={styles.buttonGroup}>
                  <button 
                    onClick={() => { clearError(); startCamera(); }}
                    className="btn btn-primary"
                    aria-label={t('common:buttons.tryAgain')}
                  >
                    🔄 {t('common:buttons.tryAgain')}
                  </button>
                  <button
                    onClick={stopCamera}
                    className="btn btn-control"
                    aria-label={t('camera:buttons.cancel.close')}
                  >
                    {t('common:buttons.cancel')}
                  </button>
                </div>
              </div>
            ) : (
              <>
                <div className={styles.videoContainer}>
                  <video
                    ref={videoRef}
                    className={styles.video}
                    autoPlay
                    muted
                    playsInline
                    aria-label={t('camera:video.preview')}
                  />
                  {!stream && (
                    <div
                      className={styles.loadingOverlay}
                      aria-live="polite"
                    >
                      <div className={styles.loadingContent}>
                        <div className={styles.spinner} aria-hidden="true"></div>
                        <p>{t('camera:video.loading.starting')}</p>
                        <p className={styles.loadingHint}>{t('camera:video.loading.hint')}</p>
                      </div>
                    </div>
                  )}
                </div>

                <div className={styles.buttonGroup}>
                  <button
                    onClick={handleCapturePhoto}
                    disabled={!stream}
                    className="btn btn-primary"
                    aria-label={t('camera:buttons.capture')}
                  >
                    <Camera size={16} aria-hidden="true" />
                    {t('common:buttons.capture')}
                  </button>
                  <button
                    onClick={flipCamera}
                    disabled={!stream}
                    className="btn btn-control"
                    aria-label={facingMode === 'user' ? t('camera:buttons.flip.toBack') : t('camera:buttons.flip.toFront')}
                    title={facingMode === 'user' ? t('camera:buttons.flip.toBack') : t('camera:buttons.flip.toFront')}
                  >
                    <RotateCcw size={16} aria-hidden="true" />
                    {t('common:buttons.flip')}
                  </button>
                  <button
                    onClick={stopCamera}
                    className="btn btn-control"
                    aria-label={t('camera:buttons.cancel.cancelAndClose')}
                  >
                    {t('common:buttons.cancel')}
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}

      <canvas 
        ref={captureCanvasRef} 
        style={{ display: 'none' }} 
        aria-hidden="true"
      />
    </>
  );
};

