import { useState, useRef, useCallback, useEffect } from 'react';
import { CameraError, CameraErrorType, UploadedImage, CanvasConfig } from '../types';
import { calculateInitialScale } from '../utils/imageProcessing';

const getCameraErrorDetails = (errorName: string): Pick<CameraError, 'message' | 'help'> => {
  switch (errorName as CameraErrorType) {
    case 'NotAllowedError':
    case 'PermissionDeniedError':
      return {
        message: 'Camera permission denied',
        help: 'Please allow camera access and try again. Look for a camera icon in your browser\'s address bar or check your site permissions.',
      };
    case 'NotFoundError':
    case 'DevicesNotFoundError':
      return {
        message: 'No camera found',
        help: 'Please make sure your device has a camera connected.',
      };
    case 'NotSupportedError':
      return {
        message: 'Camera not supported',
        help: 'Your browser doesn\'t support camera access. Try using Chrome, Firefox, or Safari.',
      };
    case 'NotReadableError':
    case 'TrackStartError':
      return {
        message: 'Camera in use',
        help: 'Close other apps using your camera and try again.',
      };
    default:
      return {
        message: 'Camera access failed',
        help: 'Please check your camera permissions and try again.',
      };
  }
};

export const useCamera = (config: CanvasConfig) => {
  const [isCapturing, setIsCapturing] = useState(false);
  const [cameraError, setCameraError] = useState<CameraError | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [availableCameras, setAvailableCameras] = useState<MediaDeviceInfo[]>([]);
  const [selectedCameraId, setSelectedCameraId] = useState<string | null>(null);
  const [isEnumerating, setIsEnumerating] = useState(false);
  const [isUserSelection, setIsUserSelection] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const captureCanvasRef = useRef<HTMLCanvasElement>(null);

  // Load saved camera preference
  useEffect(() => {
    const savedCameraId = localStorage.getItem('preferredCameraId');
    if (savedCameraId) {
      setSelectedCameraId(savedCameraId);
    }
  }, []);

  // Enumerate available cameras
  const enumerateCameras = useCallback(async () => {
    try {
      setIsEnumerating(true);

      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
        console.warn('Device enumeration not supported');
        return;
      }

      const devices = await navigator.mediaDevices.enumerateDevices();
      const videoDevices = devices.filter(device => device.kind === 'videoinput');

      setAvailableCameras(videoDevices);

      // Auto-select first external camera or fallback to first available (only if no user selection)
      if (videoDevices.length > 0 && !selectedCameraId && !isUserSelection) {
        const externalCamera = videoDevices.find(device => 
          device.label.toLowerCase().includes('usb') || 
