          (!device.label.toLowerCase().includes('facetime') &&
          !device.label.toLowerCase().includes('built-in'))
        );

        const preferredCamera = externalCamera || videoDevices[0];
        setSelectedCameraId(preferredCamera.deviceId);
        localStorage.setItem('preferredCameraId', preferredCamera.deviceId);
      }

      // If we have a saved camera ID but it's not in the current device list,
      // reset to first available camera (only if not a user selection in progress)
      if (selectedCameraId && videoDevices.length > 0 && !isUserSelection) {
        const isSelectedCameraAvailable = videoDevices.some(device => device.deviceId === selectedCameraId);
        if (!isSelectedCameraAvailable) {
          console.log('Previously selected camera not available, selecting first available');
          const firstCamera = videoDevices[0];
          setSelectedCameraId(firstCamera.deviceId);
          localStorage.setItem('preferredCameraId', firstCamera.deviceId);
        }
      }
    } catch (error) {
      console.error('Failed to enumerate cameras:', error);
    } finally {
      setIsEnumerating(false);
    }
  }, [selectedCameraId, isUserSelection]);

  // Enumerate cameras when component mounts
  useEffect(() => {
    enumerateCameras();
  }, [enumerateCameras]);

