    }

    if (lowerLabel.includes('microsoft')) {
      if (lowerLabel.includes('lifecam')) return 'Microsoft LifeCam';
      return cleanName.startsWith('Microsoft') ? cleanName : `Microsoft ${cleanName}`;
    }

    // Generic external camera detection
    if (lowerLabel.includes('usb') || (!lowerLabel.includes('built') && !lowerLabel.includes('internal'))) {
      // If we have a meaningful name after cleanup, use it
      if (cleanName && cleanName.length > 2 && !cleanName.match(/^(web|camera|cam)$/i)) {
        return cleanName;
      }
      return 'External Camera';
    }

    // Fallback: use cleaned name or generic name
    if (cleanName && cleanName.length > 2) {
      return cleanName;
    }

    return `Camera ${availableCameras.indexOf(camera) + 1}`;
  }, [availableCameras]);

  return {
    isCapturing,
    cameraError,
    stream,
    facingMode,
    availableCameras,
    selectedCameraId,
    isEnumerating,
    videoRef,
    captureCanvasRef,
    startCamera,
    stopCamera,
    capturePhoto,
    clearError,
    flipCamera,
    selectCamera,
    getCameraDisplayName,
    enumerateCameras,
  };
};

