   201→      const errorDetails = getCameraErrorDetails(error.name);
   202→      setCameraError({
   203→        ...errorDetails,
   204→        name: error.name,
   205→      });
   206→    }
   207→  }, [facingMode, selectedCameraId, enumerateCameras, isUserSelection]);
   208→
   209→  const stopCamera = useCallback(() => {
   210→    if (stream) {
   211→      stream.getTracks().forEach(track => track.stop());
   212→      setStream(null);
   213→    }
   214→    
   215→    if (videoRef.current) {
   216→      videoRef.current.srcObject = null;
   217→    }
   218→    
   219→    setIsCapturing(false);
   220→    setCameraError(null);
   221→  }, [stream]);
   222→
   223→  const capturePhoto = useCallback((): Promise<UploadedImage & { initialScale: number }> => {
   224→    return new Promise((resolve, reject) => {
   225→      if (!videoRef.current || !captureCanvasRef.current) {
   226→        reject(new Error('Camera or canvas not available'));
   227→        return;
   228→      }
