   289→          }, 100);
   290→        }
   291→      }
   292→    }
   293→  }, [isCapturing, facingMode, stopCamera, startCamera, availableCameras, selectedCameraId]);
   294→
   295→  const selectCamera = useCallback((deviceId: string) => {
   296→    console.log('User selecting camera:', deviceId);
