   298→    
   299→    // Mark this as a user selection to prevent auto-sync override
   300→    setIsUserSelection(true);
   301→    
   302→    if (wasCapturing) {
   303→      stopCamera();
   304→    }
   305→    
   306→    // Update state immediately
   307→    setSelectedCameraId(deviceId);
   308→    localStorage.setItem('preferredCameraId', deviceId);
   309→    
   310→    if (wasCapturing) {
   311→      // Pass the deviceId directly to avoid stale state issues
