   314→      }, 100);
   315→    }
   316→  }, [isCapturing, stopCamera, startCamera]);
   317→
   318→  const getCameraDisplayName = useCallback((camera: MediaDeviceInfo): string => {
   319→    if (!camera.label) {
   320→      return `Camera ${availableCameras.indexOf(camera) + 1}`;
   321→    }
   322→    
   323→    const label = camera.label;
   324→    const lowerLabel = label.toLowerCase();
   325→    
   326→    // Built-in camera detection
