   328→      return 'Built-in Camera';
   329→    }
   330→    
   331→    // Clean up the label by removing technical artifacts
   332→    let cleanName = label
   333→      // Remove USB identifiers and hex codes
   334→      .replace(/USB\d+\.\d+\s*/gi, '')
   335→      .replace(/\([0-9a-fA-F]{4}:[0-9a-fA-F]{4}\)/g, '')
   336→      .replace(/\([0-9a-fA-F]+:[0-9a-fA-F]+\)/g, '')
   337→      // Remove common technical prefixes
   338→      .replace(/^(HD|FHD|UHD|4K)\s+/gi, '')
   339→      .replace(/^(USB|Video|Webcam|Camera)\s+/gi, '')
   340→      // Remove trailing technical suffixes
   341→      .replace(/\s+(Camera|Webcam|Device)$/gi, '')
   342→      // Remove version numbers and extra spaces
   343→      .replace(/\s+v?\d+(\.\d+)*\s*$/gi, '')
   344→      .replace(/\s{2,}/g, ' ')
   345→      .trim();
   346→    
   347→    // Handle common camera brands and models
   348→    if (lowerLabel.includes('logitech')) {
   349→      if (lowerLabel.includes('c920')) return 'Logitech HD Pro C920';
   350→      if (lowerLabel.includes('c922')) return 'Logitech C922 Pro';
   351→      if (lowerLabel.includes('c930')) return 'Logitech C930e';
   352→      if (lowerLabel.includes('brio')) return 'Logitech Brio';
   353→      return cleanName.startsWith('Logitech') ? cleanName : `Logitech ${cleanName}`;
   354→    }
   355→    
   356→    if (lowerLabel.includes('microsoft')) {
   357→      if (lowerLabel.includes('lifecam')) return 'Microsoft LifeCam';
   358→      return cleanName.startsWith('Microsoft') ? cleanName : `Microsoft ${cleanName}`;
   359→    }
   360→    
   361→    // Generic external camera detection
   362→    if (lowerLabel.includes('usb') || (!lowerLabel.includes('built') && !lowerLabel.includes('internal'))) {
   363→      // If we have a meaningful name after cleanup, use it
   364→      if (cleanName && cleanName.length > 2 && !cleanName.match(/^(web|camera|cam)$/i)) {
   365→        return cleanName;
   366→      }
   367→      return 'External Camera';
   368→    }
   369→    
   370→    // Fallback: use cleaned name or generic name
   371→    if (cleanName && cleanName.length > 2) {
   372→      return cleanName;
   373→    }
   374→    
   375→    return `Camera ${availableCameras.indexOf(camera) + 1}`;
   376→  }, [availableCameras]);
   377→
