.camera-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.8);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.camera-modal {
  background: #031633;
  border-radius: 12px;
  padding: 1.5rem;
  width: min(420px, 95vw);
  display: flex;
  flex-direction: column;
  gap: 1rem;
