import { useState, useCallback, useEffect, useRef, CSSProperties } from 'react'
import { useTranslation } from 'react-i18next'
import { CameraModal } from './CameraModal'

interface ProfilePictureEditorProps {
  currentPicture: string | null
  onUpload: (blob: Blob) => Promise<void>
  isUploading: boolean
}

interface ImageState {
  width: number
  height: number
  element: HTMLImageElement
}

// Fix 6: module-level constant instead of per-render `const size = 200`
const EDITOR_SIZE = 200

export function ProfilePictureEditor({
  currentPicture,
  onUpload,
  isUploading,
}: ProfilePictureEditorProps): JSX.Element {
  const { t } = useTranslation()

  const [imageState, setImageState] = useState<ImageState | null>(null)
  const [scale, setScale] = useState(1)
  const [position, setPosition] = useState({ x: 0, y: 0 })
  const [isDragging, setIsDragging] = useState(false)
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 })
  const [initialPosition, setInitialPosition] = useState({ x: 0, y: 0 })
  const [scaleRange, setScaleRange] = useState({ min: 1, max: 1 })
  const [zoomValue, setZoomValue] = useState(0)
  const [blob, setBlob] = useState<Blob | null>(null)
  const [cameraOpen, setCameraOpen] = useState(false)

  const fileInputRef = useRef<HTMLInputElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const editorRef = useRef<HTMLDivElement>(null)

  // Fix 1: Draw canvas and export blob in one effect — toBlob() always captures
  // the freshly painted frame, eliminating the race condition between two effects.
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    ctx.clearRect(0, 0, EDITOR_SIZE, EDITOR_SIZE)

    if (!imageState) {
      ctx.fillStyle = '#1e2a4a'
      ctx.beginPath()
      ctx.arc(EDITOR_SIZE / 2, EDITOR_SIZE / 2, EDITOR_SIZE / 2, 0, Math.PI * 2)
      ctx.fill()
      ctx.fillStyle = 'rgba(255,255,255,0.3)'
      ctx.font = `${EDITOR_SIZE / 3}px sans-serif`
      ctx.textAlign = 'center'
      ctx.textBaseline = 'middle'
      ctx.fillText('＋', EDITOR_SIZE / 2, EDITOR_SIZE / 2)
      return
    }

    ctx.save()
    ctx.beginPath()
    ctx.arc(EDITOR_SIZE / 2, EDITOR_SIZE / 2, EDITOR_SIZE / 2, 0, Math.PI * 2)
    ctx.clip()
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, EDITOR_SIZE, EDITOR_SIZE)
    ctx.translate(EDITOR_SIZE / 2 + position.x, EDITOR_SIZE / 2 + position.y)
    ctx.scale(scale, scale)
    ctx.drawImage(
      imageState.element,
      -imageState.width / 2,
      -imageState.height / 2,
      imageState.width,
      imageState.height
    )
    ctx.restore()

    // Export blob after drawing — always captures the freshly painted frame
    canvas.toBlob(b => {
      if (b) setBlob(b)
    }, 'image/png')
  }, [imageState, scale, position])

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0]
      if (!file) return

      const reader = new FileReader()
      reader.onload = ev => {
        const result = ev.target?.result
        if (typeof result !== 'string') return
        const img = new Image()
        img.onload = () => {
          const w = img.naturalWidth
          const h = img.naturalHeight
          // Fix 3: apply 0.8 factor twice to give more zoom-out room for repositioning
          const minScale =
            Math.max(EDITOR_SIZE / w, EDITOR_SIZE / h) * 0.8 * 0.8
          const maxScale = Math.min(w / EDITOR_SIZE, h / EDITOR_SIZE)
          // Fix 4: removed unused `src` field from ImageState
          setImageState({ width: w, height: h, element: img })
          setScaleRange({ min: minScale, max: Math.max(minScale, maxScale) })
          setScale(minScale)
          setPosition({ x: 0, y: 0 })
          setZoomValue(0)
        }
        img.src = result
      }
      reader.readAsDataURL(file)
    },
    []
  )

  const loadImageFromUrl = useCallback(
    (dataURL: string) => {
      const img = new Image()
      img.onload = () => {
        const w = img.naturalWidth
        const h = img.naturalHeight
        const minScale = Math.max(EDITOR_SIZE / w, EDITOR_SIZE / h) * 0.8 * 0.8
        const maxScale = Math.min(w / EDITOR_SIZE, h / EDITOR_SIZE)
        setImageState({ width: w, height: h, element: img })
        setScaleRange({ min: minScale, max: Math.max(minScale, maxScale) })
        setScale(minScale)
        setPosition({ x: 0, y: 0 })
        setZoomValue(0)
      }
      img.src = dataURL
    },
    [],
  )

  const handleMouseDown = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (!imageState || !editorRef.current) return
      setIsDragging(true)
      const rect = editorRef.current.getBoundingClientRect()
      setDragStart({
        x: e.clientX - (rect.left + rect.width / 2),
        y: e.clientY - (rect.top + rect.height / 2),
      })
      setInitialPosition(position)
    },
    [imageState, position]
  )

  const handleMouseMove = useCallback(
    (e: MouseEvent) => {
      if (!isDragging || !editorRef.current) return
      const rect = editorRef.current.getBoundingClientRect()
      const offsetX = e.clientX - (rect.left + rect.width / 2)
      const offsetY = e.clientY - (rect.top + rect.height / 2)
      setPosition({
        x: initialPosition.x + offsetX - dragStart.x,
        y: initialPosition.y + offsetY - dragStart.y,
      })
    },
    [isDragging, dragStart, initialPosition]
  )

  const handleMouseUp = useCallback(() => setIsDragging(false), [])

  // Fix 2: touch handlers for mobile drag support
  const handleTouchStart = useCallback(
    (e: React.TouchEvent<HTMLDivElement>) => {
      if (!imageState || !editorRef.current) return
      const touch = e.touches[0]
      if (!touch) return
      setIsDragging(true)
      const rect = editorRef.current.getBoundingClientRect()
      setDragStart({
        x: touch.clientX - (rect.left + rect.width / 2),
        y: touch.clientY - (rect.top + rect.height / 2),
      })
      setInitialPosition(position)
    },
    [imageState, position]
  )

  const handleTouchMove = useCallback(
    (e: TouchEvent) => {
      if (!isDragging || !editorRef.current) return
      e.preventDefault()
      const touch = e.touches[0]
      if (!touch) return
      const rect = editorRef.current.getBoundingClientRect()
      const offsetX = touch.clientX - (rect.left + rect.width / 2)
      const offsetY = touch.clientY - (rect.top + rect.height / 2)
      setPosition({
        x: initialPosition.x + offsetX - dragStart.x,
        y: initialPosition.y + offsetY - dragStart.y,
      })
    },
    [isDragging, dragStart, initialPosition]
  )

  const handleTouchEnd = useCallback(() => setIsDragging(false), [])

  useEffect(() => {
    document.addEventListener('mousemove', handleMouseMove)
    document.addEventListener('mouseup', handleMouseUp)
    // Fix 2: passive: false so e.preventDefault() can block page scroll during drag
    document.addEventListener('touchmove', handleTouchMove, { passive: false })
    document.addEventListener('touchend', handleTouchEnd)
    return () => {
      document.removeEventListener('mousemove', handleMouseMove)
      document.removeEventListener('mouseup', handleMouseUp)
      document.removeEventListener('touchmove', handleTouchMove)
      document.removeEventListener('touchend', handleTouchEnd)
    }
  }, [handleMouseMove, handleMouseUp, handleTouchMove, handleTouchEnd])

  // Fix 5: wrap handleZoom in useCallback
  const handleZoom = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const v = parseFloat(e.target.value)
      setZoomValue(v)
      setScale(scaleRange.min * Math.pow(scaleRange.max / scaleRange.min, v))
    },
    [scaleRange]
  )

  const editorStyle: CSSProperties = {
    width: EDITOR_SIZE,
    height: EDITOR_SIZE,
    borderRadius: '50%',
    overflow: 'hidden',
    cursor: imageState ? 'move' : 'pointer',
    border: '2px solid rgba(255,255,255,0.15)',
    flexShrink: 0,
  }

  return (
    <div className="avatar-editor">
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        onChange={handleFileChange}
        style={{ display: 'none' }}
      />

      <div
        ref={editorRef}
        style={editorStyle}
        onMouseDown={handleMouseDown}
        onTouchStart={handleTouchStart}
        onClick={() => {
          if (!imageState) fileInputRef.current?.click()
        }}
        tabIndex={!imageState ? 0 : undefined}
        role={!imageState ? 'button' : undefined}
        aria-label={!imageState ? t('settings.picture_select') : undefined}
        onKeyDown={
          !imageState
            ? e => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault()
                  fileInputRef.current?.click()
                }
              }
            : undefined
        }
      >
        <canvas
          ref={canvasRef}
          width={EDITOR_SIZE}
          height={EDITOR_SIZE}
          style={{ display: 'block' }}
        />
      </div>

      <div className="avatar-editor-controls">
        {currentPicture && !imageState && (
          <div className="avatar-current">
            {/* Fix 7: meaningful alt text instead of empty string */}
            <img
              src={currentPicture}
              alt={t('settings.picture_current')}
              className="avatar-current-img"
            />
            <span className="avatar-current-label">
              {t('settings.picture_current')}
            </span>
          </div>
        )}

        <input
          type="range"
          min={0}
          max={1}
          step={0.01}
          value={zoomValue}
          onChange={handleZoom}
          disabled={!imageState}
          className="avatar-zoom-slider"
        />

        <div className="avatar-editor-buttons">
          <button
            type="button"
            className="cta-button cta-button--secondary"
            onClick={() => fileInputRef.current?.click()}
          >
            {imageState
              ? t('settings.picture_change')
              : t('settings.picture_select')}
          </button>

          <button
            type="button"
            className="cta-button cta-button--secondary"
            onClick={() => setCameraOpen(true)}
          >
            {t('settings.picture_camera')}
          </button>

          {imageState && (
            <button
              type="button"
              className="cta-button"
              onClick={() => {
                if (blob) void onUpload(blob)
              }}
              disabled={!blob || isUploading}
            >
              {isUploading
                ? t('settings.picture_uploading')
                : t('settings.picture_upload')}
            </button>
          )}
        </div>
      </div>

      {cameraOpen && (
        <CameraModal
          onCapture={(dataURL) => { loadImageFromUrl(dataURL); setCameraOpen(false) }}
          onClose={() => setCameraOpen(false)}
        />
      )}
    </div>
  )
}

import { useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import { useCamera } from '../useCamera'

interface CameraModalProps {
  onCapture: (_dataURL: string) => void
  onClose: () => void
}

export function CameraModal({ onCapture, onClose }: CameraModalProps): JSX.Element {
  const { t } = useTranslation()
  const {
    stream,
    cameraError,
    videoRef,
    captureCanvasRef,
    startCamera,
    stopCamera,
    capturePhoto,
    flipCamera,
    showFlip,
  } = useCamera()

  // Start camera on mount, stop on unmount
  useEffect(() => {
    void startCamera()
    return () => stopCamera()
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const handleCapture = () => {
    const dataURL = capturePhoto()
    if (dataURL) onCapture(dataURL)
  }

  const handleClose = () => {
    stopCamera()
    onClose()
  }

  // SVG mask: full rect minus centred circle
  // Circle radius = 40% of viewBox (so diameter = 80% of width)
  const maskCircle = (
    <svg
      className="camera-svg-mask"
      viewBox="0 0 100 100"
      preserveAspectRatio="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        fillRule="evenodd"
        fill="rgba(0,0,0,0.55)"
        d="M0,0 H100 V100 H0 Z M10,50 a40,40 0 1,0 80,0 a40,40 0 1,0 -80,0"
      />
      <circle
        cx="50" cy="50" r="40"
        fill="none"
        stroke="rgba(255,255,255,0.5)"
        strokeWidth="0.5"
        vectorEffect="non-scaling-stroke"
      />
    </svg>
  )

  return (
    <div className="camera-modal-overlay" onClick={(e) => { if (e.target === e.currentTarget) handleClose() }}>
      <div className="camera-modal">
        <p className="camera-modal-title">{t('camera.title')}</p>

        <div className="camera-video-wrapper">
          <video
            ref={videoRef}
            className="camera-video"
            autoPlay
            muted
            playsInline
          />
          {maskCircle}
          {!stream && !cameraError && (
            <div className="camera-loading">
              <div className="camera-spinner" />
              <span>{t('camera.loading')}</span>
            </div>
          )}
        </div>

        {cameraError && (
          <div className="camera-error">
            {t(`camera.${cameraError.message}`)}
          </div>
        )}

        <div className="camera-buttons">
          {showFlip && (
            <button
              type="button"
              className="cta-button cta-button--secondary"
              onClick={flipCamera}
              disabled={!stream}
            >
              ↺ {t('camera.flip')}
            </button>
          )}
          <button
            type="button"
            className="cta-button"
            onClick={handleCapture}
            disabled={!stream}
          >
            {t('camera.capture')}
          </button>
          <button
            type="button"
            className="cta-button cta-button--secondary"
            onClick={handleClose}
          >
            ✕
          </button>
        </div>

        <canvas ref={captureCanvasRef} style={{ display: 'none' }} />
      </div>
    </div>
  )
}

import { useState, useRef, useCallback, useEffect } from 'react'

interface CameraError {
  message: string
  help: string
}

const getErrorDetails = (errorName: string): CameraError => {
  switch (errorName) {
    case 'NotAllowedError':
    case 'PermissionDeniedError':
      return { message: 'error_permission', help: '' }
    case 'NotFoundError':
    case 'DevicesNotFoundError':
      return { message: 'error_not_found', help: '' }
    case 'NotReadableError':
    case 'TrackStartError':
      return { message: 'error_in_use', help: '' }
    default:
      return { message: 'error_generic', help: '' }
  }
}

const isMobile = (): boolean =>
  /Android|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
    navigator.userAgent
  )

export function useCamera() {
  const [isCapturing, setIsCapturing] = useState(false)
  const [stream, setStream] = useState<MediaStream | null>(null)
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>(
    'environment'
  )
  const [availableCameras, setAvailableCameras] = useState<MediaDeviceInfo[]>(
    []
  )
  const [selectedCameraId, setSelectedCameraId] = useState<string | null>(null)
  const [cameraError, setCameraError] = useState<CameraError | null>(null)

  const videoRef = useRef<HTMLVideoElement>(null)
  const captureCanvasRef = useRef<HTMLCanvasElement>(null)

  // Enumerate cameras after first getUserMedia call (labels only available after permission)
  const enumerateCameras = useCallback(async () => {
    if (!navigator.mediaDevices?.enumerateDevices) return
    const devices = await navigator.mediaDevices.enumerateDevices()
    const cameras = devices.filter(d => d.kind === 'videoinput')
    setAvailableCameras(cameras)
  }, [])

  const startCamera = useCallback(
    async (deviceId?: string, facingModeOverride?: 'user' | 'environment') => {
      setIsCapturing(true)
      setCameraError(null)

      try {
        if (!navigator.mediaDevices?.getUserMedia) {
          throw Object.assign(new Error(), { name: 'NotSupportedError' })
        }

        const videoConstraints: MediaTrackConstraints = deviceId
          ? { deviceId: { exact: deviceId } }
          : isMobile()
            ? { facingMode: facingModeOverride ?? facingMode }
            : { width: { ideal: 1280 }, height: { ideal: 720 } }

        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: videoConstraints,
        })
        setStream(mediaStream)

        // Sync selectedCameraId to the actual active camera
        const videoTrack = mediaStream.getVideoTracks()[0]
        if (videoTrack) {
          const actualDeviceId = videoTrack.getSettings().deviceId
          if (actualDeviceId) setSelectedCameraId(actualDeviceId)
        }

        await enumerateCameras()

        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream
          await videoRef.current.play()
        }
      } catch (err: any) {
        setIsCapturing(false)
        setCameraError(getErrorDetails(err?.name ?? ''))
      }
    },
    [facingMode, enumerateCameras]
  )

  const stopCamera = useCallback(() => {
    stream?.getTracks().forEach(t => t.stop())
    setStream(null)
    setIsCapturing(false)
    setCameraError(null)
    if (videoRef.current) videoRef.current.srcObject = null
  }, [stream])

  const capturePhoto = useCallback((): string => {
    const video = videoRef.current
    const canvas = captureCanvasRef.current
    if (!video || !canvas) return ''
    canvas.width = video.videoWidth
    canvas.height = video.videoHeight
    canvas.getContext('2d')?.drawImage(video, 0, 0)
    const dataURL = canvas.toDataURL('image/jpeg', 0.9)
    stopCamera()
    return dataURL
  }, [stopCamera])

  const flipCamera = useCallback(() => {
    if (!isCapturing) return
    stopCamera()
    if (isMobile()) {
      const next = facingMode === 'environment' ? 'user' : 'environment'
      setFacingMode(next)
      setTimeout(() => void startCamera(undefined, next), 150)
    } else {
      const currentIdx = availableCameras.findIndex(
        c => c.deviceId === selectedCameraId
      )
      const next = availableCameras[(currentIdx + 1) % availableCameras.length]
      if (next) {
        setSelectedCameraId(next.deviceId)
        setTimeout(() => void startCamera(next.deviceId), 150)
      }
    }
  }, [
    isCapturing,
    facingMode,
    availableCameras,
    selectedCameraId,
    stopCamera,
    startCamera,
  ])

  // Auto-stop on unmount
  useEffect(() => {
    return () => {
      stream?.getTracks().forEach(t => t.stop())
    }
  }, [stream])

  const clearError = useCallback(() => setCameraError(null), [])

  const showFlip = isMobile() || availableCameras.length > 1

  return {
    isCapturing,
    stream,
    facingMode,
    availableCameras,
    cameraError,
    videoRef,
    captureCanvasRef,
    startCamera,
    stopCamera,
    capturePhoto,
    flipCamera,
    clearError,
    showFlip,
  }
}

